# [doc = " Assert that `predicate(mode)` returns **`true`** for every mode in `scope` and **`false`**"] # [doc = " for every mode **outside** scope — the cross-mode **negative** pattern (RFC-0034 §13)."] # [doc = ""] # [doc = " This is the mechanical implementation of the conformance contract: it catches **both**"] # [doc = " (a) the property not holding when it should (positive failure), and (b) the property holding"] # [doc = " when it should not (\"invariant fires where it doesn't apply\" — the negative failure that a"] # [doc = " simple `assert!` cannot catch)."] # [doc = ""] # [doc = " `desc` is a human-readable description of the property, included in panic messages (EXPLAIN"] # [doc = " artifact — C3/G11)."] # [doc = ""] # [doc = " # Guarantee tag: `Exact`"] # [doc = " # Fallibility: panics on mismatch (the harness's \"never-silent\" is a panic, not a Verdict,"] # [doc = "   so the failure is immediately surfaced in the test runner — consistent with Rust's test"] # [doc = "   model)"] # [doc = " # Effects: none (pure; side-effects live in `predicate`)"] # [doc = ""] # [doc = " # EXPLAIN"] # [doc = " A positive panic reports: which mode, the declared scope, and the description."] # [doc = " A negative panic reports: which mode (in scope but predicate false), the declared scope,"] # [doc = " and the description."] # [doc = ""] # [doc = " **Mutant-witness for the negative arm:** if `predicate` always returns `true` (an invariant"] # [doc = " that holds everywhere) and the scope is `FAST_ONLY`, the negative arm fires for `Balanced`"] # [doc = " and `Certified`, catching the over-broad invariant. Conversely, if `predicate` always returns"] # [doc = " `false`, the positive arm fires for `Fast`, catching the absent invariant."] # [doc = ""] # [doc = " # Example"] # [doc = " ```rust"] # [doc = " # use mycelium_std_testing::cert_mode_test::{ModeScope, assert_mode_scope};"] # [doc = " # use mycelium_core::cert_mode::CertMode;"] # [doc = " // Fast is the only mode that floors Proven to Declared:"] # [doc = " assert_mode_scope("] # [doc = "     ModeScope::FAST_ONLY,"] # [doc = "     |mode| mode == CertMode::Fast,"] # [doc = "     \"Fast is the mode that applies the floor\","] # [doc = " );"] # [doc = " ```"] pub fn assert_mode_scope (scope : ModeScope , predicate : impl Fn (CertMode) -> bool , desc : & str) { for & mode in & CertMode :: ALL { let holds = predicate (mode) ; let expected = scope . contains (mode) ; if holds && ! expected { panic ! ("cross-mode NEGATIVE failed: `{desc}` holds in {mode:?} but scope={scope:?} \
                 says it should NOT. The invariant fires where it shouldn't (RFC-0034 §13).") ; } if ! holds && expected { panic ! ("cross-mode POSITIVE failed: `{desc}` does NOT hold in {mode:?} but scope={scope:?} \
                 says it SHOULD. The invariant is absent where it must fire (RFC-0034 §13).") ; } } }

